/**
 * Environment Variable Validation Utility
 * 
 * Provides runtime validation and helpful error messages for missing environment variables
 */

export interface EnvValidationResult {
  isValid: boolean;
  missing: string[];
  errorMessage: string;
}

export function validateClientEnv(): EnvValidationResult {
  const required = [
    'NEXT_PUBLIC_SUPABASE_URL',
    'NEXT_PUBLIC_SUPABASE_ANON_KEY',
    'NEXT_PUBLIC_GHL_CLIENT_ID',
    'NEXT_PUBLIC_APP_URL',
  ];

  const missing = required.filter(key => !process.env[key]);

  if (missing.length > 0) {
    return {
      isValid: false,
      missing,
      errorMessage: `Missing required environment variables: ${missing.join(', ')}. Please configure these in your Vercel project settings.`,
    };
  }

  return {
    isValid: true,
    missing: [],
    errorMessage: '',
  };
}

export function validateServerEnv(): EnvValidationResult {
  const required = [
    'NEXT_PUBLIC_SUPABASE_URL',
    'NEXT_PUBLIC_SUPABASE_ANON_KEY',
    'SUPABASE_SERVICE_ROLE_KEY',
    'NEXT_PUBLIC_GHL_CLIENT_ID',
    'NEXT_PUBLIC_GHL_CLIENT_SECRET',
    'NEXT_PUBLIC_APP_URL',
    'GHL_WEBHOOK_SECRET',
    'ENCRYPTION_KEY',
  ];

  const missing = required.filter(key => !process.env[key]);

  if (missing.length > 0) {
    return {
      isValid: false,
      missing,
      errorMessage: `Missing required environment variables: ${missing.join(', ')}. Please configure these in your Vercel project settings.`,
    };
  }

  return {
    isValid: true,
    missing: [],
    errorMessage: '',
  };
}

export function getEnvOrThrow(key: string): string {
  const value = process.env[key];
  if (!value) {
    throw new Error(`Missing required environment variable: ${key}. Please configure this in your Vercel project settings.`);
  }
  return value;
}

export function logEnvStatus() {
  if (typeof window === 'undefined') {
    // Server-side
    console.log('Environment Variables Status (Server):');
    const serverValidation = validateServerEnv();
    if (!serverValidation.isValid) {
      console.error('❌', serverValidation.errorMessage);
    } else {
      console.log('✅ All required server environment variables are set');
    }
  } else {
    // Client-side
    console.log('Environment Variables Status (Client):');
    const clientValidation = validateClientEnv();
    if (!clientValidation.isValid) {
      console.error('❌', clientValidation.errorMessage);
    } else {
      console.log('✅ All required client environment variables are set');
    }
  }
}