import { NextRequest, NextResponse } from 'next/server';
import { createClient } from '@supabase/supabase-js';
import { getEnvOrThrow } from '@/lib/env-validation';

export async function POST(request: NextRequest) {
  try {
    // Validate environment variables first
    const supabaseUrl = getEnvOrThrow('NEXT_PUBLIC_SUPABASE_URL');
    const supabaseServiceKey = getEnvOrThrow('SUPABASE_SERVICE_ROLE_KEY');

    const { token, locationId, companyId } = await request.json();

    if (!token) {
      return NextResponse.json(
        { error: 'Missing SSO token' },
        { status: 400 }
      );
    }

    // Verify SSO token with GHL
    const ghlResponse = await fetch('https://services.leadconnectorhq.com/oauth/token/verify', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${token}`,
      },
    });

    if (!ghlResponse.ok) {
      return NextResponse.json(
        { error: 'Invalid SSO token' },
        { status: 401 }
      );
    }

    const ghlUser = await ghlResponse.json();

    // Create Supabase admin client
    const supabase = createClient(supabaseUrl, supabaseServiceKey);

    // Create or update user in Supabase
    const { data: authData, error: authError } = await supabase.auth.admin.createUser({
      email: ghlUser.email,
      email_confirm: true,
      user_metadata: {
        ghl_user_id: ghlUser.id,
        location_id: locationId,
        company_id: companyId,
      },
    });

    if (authError) {
      console.error('Supabase auth error:', authError);
      return NextResponse.json(
        { error: 'Failed to create user session' },
        { status: 500 }
      );
    }

    // Store user data in users table
    const { error: dbError } = await supabase
      .from('users')
      .upsert({
        auth_id: authData.user.id,
        ghl_user_id: ghlUser.id,
        location_id: locationId,
        company_id: companyId,
        email: ghlUser.email,
      });

    if (dbError) {
      console.error('Database error:', dbError);
    }

    // Generate session token
    const { data: sessionData, error: sessionError } = await supabase.auth.admin.generateLink({
      type: 'magiclink',
      email: ghlUser.email,
    });

    if (sessionError) {
      console.error('Session generation error:', sessionError);
      return NextResponse.json(
        { error: 'Failed to generate session' },
        { status: 500 }
      );
    }

    return NextResponse.json({
      success: true,
      session: sessionData,
    });

  } catch (error) {
    console.error('SSO authentication error:', error);
    
    // Return helpful error message for missing env vars
    if (error instanceof Error && error.message.includes('Missing required environment variable')) {
      return NextResponse.json(
        { 
          error: 'Server configuration error',
          details: error.message,
          help: 'Please ensure all environment variables are configured in Vercel project settings.'
        },
        { status: 500 }
      );
    }
    
    return NextResponse.json(
      { error: 'Internal server error' },
      { status: 500 }
    );
  }
}